// PLAN DETECT LOGIC TEST-SAFE DRAFT.
// No external calls. No write nodes. No message-send nodes.
const items = [
  { repo: 'mrhz1973/control-plane', sourceRepo: 'mrhz1973/control-plane', changedFiles: ['docs/plans/2026-05-21_1500_control-plane_pm-09-gate-c.plan.md', 'docs/MVP_STATUS.md'], currentSha: 'synthetic-cp-plan-hit', shortSha: 'synthet' },
  { repo: 'mrhz1973/dev-method', sourceRepo: 'mrhz1973/dev-method', changedFiles: ['README.md'], currentSha: 'synthetic-dev-no-plan', shortSha: 'synthet' },
  { repo: 'mrhz1973/cursor-coordinate-converter', sourceRepo: 'mrhz1973/cursor-coordinate-converter', changedFiles: ['docs/example.md'], currentSha: 'synthetic-gis-no-plan', shortSha: 'synthet' }
];
return items.map((json) => ({ json }));

const repo = String($json.repo || $json.sourceRepo || '').trim();
return {
  json: {
    event: repo === 'mrhz1973/control-plane' ? 'plan_branch_entered' : 'plan_branch_skipped',
    repo,
    changedFiles: $json.changedFiles || [],
    currentSha: $json.currentSha,
    shortSha: $json.shortSha,
    gate: 'C-plan-detect-logic-test-safe',
    activeRuntimeTarget: '40 - CP v4 multirepo polling - FILE HANDOFF SAFE TEXT - ACTIVE',
    noMessages: true,
    noWrites: true
  }
};

const inputItems = $input.all();
const output = [];
for (const item of inputItems) {
  const files = Array.isArray(item.json.changedFiles) ? item.json.changedFiles : [];
  const planFiles = files.filter((name) => /^docs\/plans\/[^/]+\.plan\.md$/.test(String(name)));
  if (!planFiles.length) {
    output.push({ json: { event: 'no_plan_detected', repo: item.json.repo, changedFiles: files, gate: 'C-plan-detect-logic-test-safe', noMessages: true, noWrites: true } });
  } else {
    for (const planPath of planFiles) {
      output.push({ json: { event: 'plan_detected', repo: item.json.repo, planPath, currentSha: item.json.currentSha, shortSha: item.json.shortSha, gate: 'C-plan-detect-logic-test-safe', nextGate: 'Gate D message delivery not authorized', noMessages: true, noWrites: true } });
    }
  }
}
return output;

return {
  json: {
    event: 'non_control_plane_repo_skipped',
    repo: $json.repo,
    changedFiles: $json.changedFiles || [],
    gate: 'C-plan-detect-logic-test-safe',
    noMessages: true,
    noWrites: true
  }
};
